-- Insert Anime
INSERT OR IGNORE INTO anime (id, title, slug, cover_image, banner_image, synopsis, year, quarter, episode_count, status, rating, popularity, created_at, updated_at)
VALUES
  ('1', 'Solo Leveling', 'solo-leveling', 'https://s4.anilist.co/file/anilistcdn/media/anime/cover/large/bx151807-it355ZgzquUd.png', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Solo+Leveling', 'They say whatever doesn''t kill you makes you stronger, but that isn''t the case for the world''s weakest hunter Sung Jinwoo. After being brutally slaughtered by monsters in a high-ranking dungeon, Jinwoo came back with the System, a program only he could see, that''s leveling him up in every way. Now, he''s inspired to discover the secrets behind his powers and the dungeon that spawned them.', 2024, 'Winter', 12, 'Completed', 8.4, 250000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('2', 'Jujutsu Kaisen Season 2', 'jujutsu-kaisen-season-2', 'https://cdn.myanimelist.net/images/anime/1792/138022l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Jujutsu+Kaisen+S2', 'The past comes to light when second-year students Satoru Gojo and Suguru Geto are tasked with escorting young Riko Amanai to Master Tengen. But when a non-sorcerer user tries to kill them, their mission to protect the Star Plasma Vessel threatens to turn them into bitter enemies and cement their destinies.', 2023, 'Summer', 23, 'Completed', 8.8, 350000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('3', 'Frieren: Beyond Journey''s End', 'frieren-beyond-journeys-end', 'https://cdn.myanimelist.net/images/anime/1015/138006l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Frieren', 'Elf mage Frieren and her courageous fellow adventurers have defeated the Demon King and brought peace to the land. But Frieren will long outlive the rest of her former party. How will she come to understand what life means to the people around her? Decades after their victory, the funeral of one of her friends confronts Frieren with her own near immortality.', 2023, 'Fall', 28, 'Completed', 9.1, 300000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('4', 'Kaiju No. 8', 'kaiju-no-8', 'https://s4.anilist.co/file/anilistcdn/media/anime/cover/large/bx153288-25FBfFJzEQ5O.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Kaiju+No.+8', 'In a world plagued by Kaiju, Kafka Hibino works as a monster sweeper. But when a parasitic Kaiju enters his body, Kafka gains the ability to transform into a monster himself. With his newfound powers, Kafka aims to join the Anti-Kaiju Defense Force and keep the promise he made to his childhood friend.', 2024, 'Spring', 12, 'Ongoing', 8.2, 180000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('5', 'Demon Slayer: Hashira Training Arc', 'demon-slayer-hashira-training-arc', 'https://s4.anilist.co/file/anilistcdn/media/anime/cover/large/bx166240-PBV7zukIHW7V.png', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Demon+Slayer', 'Tanjiro goes to see the Stone Hashira, Himejima, who intends to prepare him for the battles to come. The training to become a Hashira—a high-ranking member of the Demon Slayer Corps—is intense and demanding. Earning Himejima''s approval seems impossible, but Tanjiro won''t give up!', 2024, 'Spring', 8, 'Completed', 8.1, 200000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('6', 'Mushoku Tensei: Jobless Reincarnation II', 'mushoku-tensei-jobless-reincarnation-ii', 'https://cdn.myanimelist.net/images/anime/1823/140286l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Mushoku+Tensei', 'Following the devastating events of the previous season, Rudeus Greyrat wanders the north, aiming to make a name for himself in hopes of finding his missing mother. His journey eventually leads him to the Ranoa University of Magic, where he reunites with a familiar face and embarks on a new chapter of his life.', 2023, 'Summer', 12, 'Completed', 8.3, 160000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('7', 'Oshi no Ko', 'oshi-no-ko', 'https://cdn.myanimelist.net/images/anime/1812/134736l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Oshi+no+Ko', 'When a pregnant young starlet appears in his countryside medical clinic, Dr. Goro is determined to help her deliver safely. But a mysterious figure interferes, and Goro finds himself reborn as the idol''s son. Now, he must navigate the dark and treacherous world of the entertainment industry to uncover the truth.', 2023, 'Spring', 11, 'Completed', 8.7, 280000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('8', 'Spy x Family Season 2', 'spy-x-family-season-2', 'https://cdn.myanimelist.net/images/anime/1666/138136l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Spy+x+Family', 'World peace is at stake, and secret agent Twilight must undergo his most difficult mission yet—pretending to be a family man. Posing as a loving husband and father, he''ll infiltrate an elite school to get close to a high-profile politician. He has the perfect cover, except his wife''s a deadly assassin and neither knows each other''s identity.', 2023, 'Fall', 12, 'Completed', 8.2, 210000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('9', 'Dandadan', 'dandadan', 'https://s4.anilist.co/file/anilistcdn/media/anime/cover/large/bx171018-60q1B6GK2Ghb.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Dandadan', 'Momo Ayase is a high school girl who believes in ghosts but not aliens, while her classmate Okarun believes in aliens but not ghosts. To prove each other wrong, they visit locations associated with both the occult and extraterrestrials, only to discover that both are very real—and incredibly dangerous.', 2024, 'Fall', 12, 'Upcoming', 0, 150000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('10', 'Chainsaw Man', 'chainsaw-man', 'https://cdn.myanimelist.net/images/anime/1806/126216l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Chainsaw+Man', 'Denji''s a poor young man who''ll do anything for money, even hunting down devils with his pet devil-dog Pochita. He''s a simple man with simple dreams, drowning under a mountain of debt. But his sad life gets turned upside down one day when he''s betrayed by someone he trusts.', 2022, 'Fall', 12, 'Completed', 8.5, 400000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('11', 'Attack on Titan Final Season Part 3', 'attack-on-titan-final-season-part-3', 'https://cdn.myanimelist.net/images/anime/1759/133549l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Attack+on+Titan', 'Eren activates the Rumbling in an attempt to destroy the world. Countless Titans begin their march, trampling everything in their path. Mikasa, Armin, Reiner, and the remaining members of the Survey Corps set out to stop Eren and save humanity.', 2023, 'Spring', 2, 'Completed', 9, 420000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('12', 'My Hero Academia Season 7', 'my-hero-academia-season-7', 'https://cdn.myanimelist.net/images/anime/1838/142340l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=My+Hero+Academia', 'As the battle between heroes and villains escalates to its breaking point, Star and Stripe, the No. 1 hero of the United States of America, arrives to assist Japan against the looming threat of Tomura Shigaraki and All For One.', 2024, 'Spring', 21, 'Ongoing', 8.3, 150000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('13', 'Bocchi the Rock!', 'bocchi-the-rock', 'https://cdn.myanimelist.net/images/anime/1448/127956l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Bocchi+the+Rock', 'Hitori Gotoh is a high school girl who starts learning to play the guitar because she dreams of being in a band, but she is so socially anxious that she hasn''t made a single friend. However, her dream may come true after she meets Nijika Ijichi, who plays drums and is looking for a guitarist.', 2022, 'Fall', 12, 'Completed', 8.8, 120000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('14', 'Bleach: Thousand-Year Blood War', 'bleach-thousand-year-blood-war', 'https://cdn.myanimelist.net/images/anime/1908/135431l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Bleach+TYBW', 'When a new enemy appears, Ichigo Kurosaki jumps back onto the battlefield with his Zanpakuto to help those in need. Meanwhile, the Soul Society observes a sudden surge in the number of Hollows being destroyed in the World of the Living.', 2022, 'Fall', 13, 'Completed', 8.9, 180000, strftime('%s', 'now'), strftime('%s', 'now')),
  ('15', 'Kaguya-sama: Love is War - Ultra Romantic', 'kaguya-sama-love-is-war-ultra-romantic', 'https://cdn.myanimelist.net/images/anime/1160/122627l.jpg', 'https://placehold.co/1920x600/0f172a/f8fafc?text=Kaguya-sama', 'The elite members of Shuchiin Academy''s student council continue their competitive game of romantic cat and mouse. Kaguya Shinomiya and Miyuki Shirogane try to force each other to confess their feelings as the end of the school term approaches.', 2022, 'Spring', 13, 'Completed', 8.9, 230000, strftime('%s', 'now'), strftime('%s', 'now'));

